const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const app = express();
const port = 3000;

app.use(express.json());

// Elasticsearch client setup
const esClient = new Client({
  node: 'http://localhost:9200'
});

app.post('/search', async (req, res) => {
  const { index, query, script } = req.body;

  if (!index || !query) {
    return res.status(400).json({ error: 'Index and query are required' });
  }

  try {
    // Validate user-provided script
    if (script) {
      validateScript(script);
    }

    const searchBody = {
      query: {
        script_score: {
          query: { match_all: {} },
          script: script ? { source: script } : undefined,
          params: req.body.params || {}
        }
      }
    };

    // Merge user-provided query into the search body
    if (query) {
      searchBody.query.script_score.query = query;
    }

    const response = await esClient.search({
      index,
      body: searchBody
    });

    res.json(response);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

function validateScript(script) {
  // Simple regex to prevent script injection
  if (/script\s*=\s*(\w+)/.test(script)) {
    throw new Error('Invalid script');
  }
}

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});